import{_ as t,o as a,c as s,ae as r}from"./chunks/framework.BeVX27ge.js";const h=JSON.parse('{"title":"Stage Management","description":"","frontmatter":{},"headers":[],"relativePath":"en/admin-stages.md","filePath":"en/admin-stages.md"}'),o={name:"en/admin-stages.md"};function i(n,e,l,u,c,g){return a(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="stage-management" tabindex="-1">Stage Management <a class="header-anchor" href="#stage-management" aria-label="Permalink to &quot;Stage Management&quot;">​</a></h1><blockquote><p>Define sales practice stages, set AI evaluation standards and goals.</p></blockquote><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Sales stages are the backbone of the AI Coach practice workflow. Each stage represents a critical step in the sales conversation. AI tracks your progress and generates evaluations based on these stages.</p><blockquote><p>Only available to administrators with Stage Management permissions.</p></blockquote><h2 id="page-structure" tabindex="-1">Page Structure <a class="header-anchor" href="#page-structure" aria-label="Permalink to &quot;Page Structure&quot;">​</a></h2><p>Stage cards are ordered by their stage number:</p><ul><li><strong>Title</strong>: Format &quot;Stage N: {Stage Name}&quot;</li><li><strong>Customer Status</strong>: The psychological or behavioral state of the customer at this stage.</li><li><strong>Options</strong>: Edit / Delete buttons.</li></ul><hr><h2 id="stage-attributes" tabindex="-1">Stage Attributes <a class="header-anchor" href="#stage-attributes" aria-label="Permalink to &quot;Stage Attributes&quot;">​</a></h2><h3 id="stage-number" tabindex="-1">Stage Number <a class="header-anchor" href="#stage-number" aria-label="Permalink to &quot;Stage Number&quot;">​</a></h3><ul><li>Determines the sequence. Must be a positive integer and unique. Cannot be modified after creation.</li></ul><h3 id="stage-description" tabindex="-1">Stage Description <a class="header-anchor" href="#stage-description" aria-label="Permalink to &quot;Stage Description&quot;">​</a></h3><ul><li>The name and goal of the stage (e.g., &quot;Ice-breaking&quot;, &quot;Needs Discovery&quot;).</li></ul><h3 id="current-customer-status" tabindex="-1">Current Customer Status <a class="header-anchor" href="#current-customer-status" aria-label="Permalink to &quot;Current Customer Status&quot;">​</a></h3><ul><li>Describes the customer&#39;s mindset, allowing AI to simulate realistic reactions (e.g., &quot;Customer is hesitant and has not built trust yet&quot;).</li></ul><hr><h2 id="actions" tabindex="-1">Actions <a class="header-anchor" href="#actions" aria-label="Permalink to &quot;Actions&quot;">​</a></h2><ul><li><strong>Add Stage</strong>: Click &quot;Add Stage&quot;. Fill in Number, Description, and Status.</li><li><strong>Edit Stage</strong>: Click &quot;Edit&quot; on the card (Stage Number cannot be changed).</li><li><strong>Delete Stage</strong>: Click &quot;Delete&quot;. This may affect the display of historical evaluations.</li></ul><hr><h2 id="design-recommendations" tabindex="-1">Design Recommendations <a class="header-anchor" href="#design-recommendations" aria-label="Permalink to &quot;Design Recommendations&quot;">​</a></h2><ol><li><strong>Logical Progression</strong>: From easy to hard, mimicking the natural sales flow.</li><li><strong>Clear Goals</strong>: Each stage should have specific, measurable objectives.</li><li><strong>Realistic Descriptions</strong>: Customer status must accurately reflect their actual mindset.</li><li><strong>Appropriate Length</strong>: 3-7 stages are recommended for optimal practice.</li></ol>',22)])])}const m=t(o,[["render",i]]);export{h as __pageData,m as default};
